SELECT tournament_id, total_entries
FROM tournaments
ORDER BY total_entries DESC;

SELECT total_entries
FROM tournaments
WHERE tournament_id = 1;

SELECT tournament_id, total_entries
FROM tournaments
ORDER BY total_entries DESC;

SELECT AVG(prize_amount) AS average_treasure
FROM results
WHERE tournament_id = 1;

SELECT SUM(prize_amount) AS total_prize_won
FROM results
WHERE is_winner = 1;

SELECT AVG(prize_amount) AS average_prize_amount
FROM results
WHERE tournament_id = 0;
